class SamlAuthenticationFilter extends AbstractAuthenticationProcessingFilter {

    SamlAuthenticationFilter() {
        super(new AntPathRequestMatcher("/saml/acs", HttpMethod.POST.name()));
    }

    @Override
    public Authentication attemptAuthentication(HttpServletRequest request, HttpServletResponse response)
        throws AuthenticationException {
        String samlResponse = request.getParameter("SAMLResponse");
        if (!StringUtils.hasText(samlResponse)) {
            throw new BadCredentialsException("Missing SAMLResponse");
        }
        SamlAuthenticationToken authRequest = new SamlAuthenticationToken(samlResponse);
        authRequest.setDetails(authenticationDetailsSource.buildDetails(request));
        return this.getAuthenticationManager().authenticate(authRequest);
    }

    @Override
    protected void successfulAuthentication(HttpServletRequest request,
                                            HttpServletResponse response,
                                            FilterChain chain,
                                            Authentication authResult) throws java.io.IOException, ServletException {
        super.successfulAuthentication(request, response, chain, authResult);
        if (authResult instanceof SamlAuthenticatedPrincipal principal) {
            HttpSession session = request.getSession(true);
            session.setAttribute("SAML_NAME_ID", principal.getName());
            session.setAttribute("SAML_ATTRIBUTES", principal.getAttributes());
            session.setAttribute("SAML_AUTHENTICATED_AT", principal.getAuthenticatedAt().toString());
        }
    }
}

class SamlAuthenticationToken extends AbstractAuthenticationToken {
    private final Object principal;
    private final String samlResponse;

    SamlAuthenticationToken(String samlResponse) {
        super(Collections.emptyList());
        this.principal = null;
        this.samlResponse = samlResponse;
        setAuthenticated(false);
    }

    SamlAuthenticationToken(SamlAuthenticatedPrincipal principal, Collection<SimpleGrantedAuthority> authorities) {
        super(authorities);
        this.principal = principal;
        this.samlResponse = null;
        setAuthenticated(true);
    }

    @Override
    public Object getCredentials() {
        return samlResponse;
    }

    @Override
    public Object getPrincipal() {
        return principal;
    }
}

