@Component
class SamlAuthenticationProvider implements AuthenticationProvider {

    private final SamlResponseService samlResponseService;

    SamlAuthenticationProvider(SamlResponseService samlResponseService) {
        this.samlResponseService = samlResponseService;
    }

    @Override
    public Authentication authenticate(Authentication authentication) throws AuthenticationException {
        String encodedResponse = (String) authentication.getCredentials();
        SamlAssertion assertion = samlResponseService.parseAndValidate(encodedResponse);

        List<SimpleGrantedAuthority> authorities = new ArrayList<>();
        authorities.add(new SimpleGrantedAuthority("ROLE_USER"));

        List<String> roles = assertion.attributes().get("Role");
        if (roles != null) {
            for (String role : roles) {
                if (StringUtils.hasText(role)) {
                    String normalized = role.startsWith("ROLE_") ? role : "ROLE_" + role.toUpperCase().replace('-', '_').replace(' ', '_');
                    authorities.add(new SimpleGrantedAuthority(normalized));
                }
            }
        }

        return new SamlAuthenticatedPrincipal(assertion.nameId(), assertion.attributes(), authorities);
    }

    @Override
    public boolean supports(Class<?> authentication) {
        return SamlAuthenticationToken.class.isAssignableFrom(authentication);
    }
}

@Service
class SamlResponseService {

    public SamlAssertion parseAndValidate(String base64SamlResponse) {
        try {
            byte[] decoded = Base64.getDecoder().decode(base64SamlResponse);
            Document document = parseXmlSecurely(decoded);

            Element response = document.getDocumentElement();
            if (response == null || !"Response".equals(response.getLocalName())) {
                throw new BadCredentialsException("Invalid SAML Response");
            }

            Element assertion = findFirstElement(response, "Assertion");
            if (assertion == null) {
                throw new BadCredentialsException("Missing Assertion");
            }

            validateConditions(assertion);

            String nameId = extractNameId(assertion);
            if (!StringUtils.hasText(nameId)) {
                throw new BadCredentialsException("Missing NameID");
            }

            Map<String, List<String>> attributes = extractAttributes(assertion);
            return new SamlAssertion(nameId, attributes);
        } catch (BadCredentialsException ex) {
            throw ex;
        } catch (Exception ex) {
            throw new BadCredentialsException("Failed to process SAML Response", ex);
        }
    }

    private Document parseXmlSecurely(byte[] xmlBytes) throws Exception {
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
        factory.setNamespaceAware(true);
        factory.setXIncludeAware(false);
        factory.setExpandEntityReferences(false);
        factory.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);
        factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
        factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
        factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);

        DocumentBuilder builder = factory.newDocumentBuilder();
        return builder.parse(new ByteArrayInputStream(xmlBytes));
    }

    private void validateConditions(Element assertion) {
        Element conditions = findFirstElement(assertion, "Conditions");
        if (conditions == null) {
            return;
        }

        String notBefore = conditions.getAttribute("NotBefore");
        String notOnOrAfter = conditions.getAttribute("NotOnOrAfter");
        Instant now = Instant.now();

        if (StringUtils.hasText(notBefore)) {
            Instant nb = Instant.parse(notBefore);
            if (now.isBefore(nb.minusSeconds(60))) {
                throw new BadCredentialsException("Assertion not yet valid");
            }
        }

        if (StringUtils.hasText(notOnOrAfter)) {
            Instant noa = Instant.parse(notOnOrAfter);
            if (!now.isBefore(noa.plusSeconds(60))) {
                throw new BadCredentialsException("Assertion expired");
            }
        }
    }

    private String extractNameId(Element assertion) {
        Element subject = findFirstElement(assertion, "Subject");
        if (subject == null) {
            return null;
        }
        Element nameId = findFirstElement(subject, "NameID");
        return nameId != null ? nameId.getTextContent().trim() : null;
    }

    private Map<String, List<String>> extractAttributes(Element assertion) {
        Map<String, List<String>> attributes = new LinkedHashMap<>();
        Element attributeStatement = findFirstElement(assertion, "AttributeStatement");
        if (attributeStatement == null) {
            return attributes;
        }

        for (Element attr = findFirstElement(attributeStatement, "Attribute");
             attr != null;
             attr = findNextSiblingElement(attr, "Attribute")) {

            String name = attr.getAttribute("Name");
            if (!StringUtils.hasText(name)) {
                continue;
            }

            List<String> values = new ArrayList<>();
            for (Element value = findFirstElement(attr, "AttributeValue");
                 value != null;
                 value = findNextSiblingElement(value, "AttributeValue")) {
                String text = value.getTextContent();
                if (text != null) {
                    values.add(text.trim());
                }
            }
            attributes.put(name, values);
        }
        return attributes;
    }

    private Element findFirstElement(Element parent, String localName) {
        for (Node child = parent.getFirstChild(); child != null; child = child.getNextSibling()) {
            if (child instanceof Element element) {
                if (localName.equals(element.getLocalName()) || localName.equals(element.getNodeName())) {
                    return element;
                }
                Element nested = findFirstElement(element, localName);
                if (nested != null) {
                    return nested;
                }
            }
        }
        return null;
    }

    private Element findNextSiblingElement(Element current, String localName) {
        for (Node node = current.getNextSibling(); node != null; node = node.getNextSibling()) {
            if (node instanceof Element element) {
                if (localName.equals(element.getLocalName()) || localName.equals(element.getNodeName())) {
                    return element;
                }
            }
        }
        return null;
    }
}

