@RestController
class HomeController {

    @GetMapping("/")
    public Map<String, Object> home(HttpServletRequest request) {
        Map<String, Object> response = new HashMap<>();
        HttpSession session = request.getSession(false);
        response.put("authenticated", request.getUserPrincipal() != null);
        response.put("principal", request.getUserPrincipal() != null ? request.getUserPrincipal().getName() : null);

        if (session != null) {
            Map<String, Object> sessionData = new HashMap<>();
            Enumeration<String> names = session.getAttributeNames();
            while (names.hasMoreElements()) {
                String name = names.nextElement();
                sessionData.put(name, session.getAttribute(name));
            }
            response.put("session", sessionData);
        } else {
            response.put("session", Collections.emptyMap());
        }
        return response;
    }
}